const body = .body || ;
const items = body.items || [];
if (!body.no_nota || !body.tgl_nota || !body.penyedia || !items.length) {
  throw new Error('no_nota, tgl_nota, penyedia, dan items wajib diisi');
}
const instansi_id = body.instansi_id || 'bapperida';
const total = body.total_nilai || items.reduce((s,i) => s + (parseFloat(i.volume)||0)*(parseFloat(i.harga_satuan)||0), 0);
const detailRows = items.map(i => ('', , , )).join(',\n');
return [{
  no_nota: body.no_nota.replace(/'/g, "''"),
  tgl_nota: body.tgl_nota,
  penyedia: body.penyedia.replace(/'/g, "''"),
  total_nilai: total,
  no_sp2d: (body.no_sp2d||'').replace(/'/g, "''"),
  kontrak: (body.kontrak||'').replace(/'/g, "''"),
  sub_kegiatan: (body.sub_kegiatan||'').replace(/'/g, "''"),
  status_spj: body.status_spj || 'belum_dikumpulkan',
  instansi_id: instansi_id,
  detail_rows: detailRows,
  items: items,
  created_by: body.created_by || 'system'
}];

const nota_id = $json[0]?.id || $json?.id || $json?.rows?.[0]?.id;
if (!nota_id) throw new Error('Gagal menyimpan nota');
const prev = $input.first().json;
const detailRows = prev.detail_rows;

return [{
  nota_id: nota_id,
  detail_rows: detailRows,
  prev: prev
}];

const body = $json.body || $json;
const rows = body.rows || [];
if (!rows.length) throw new Error('Data BKU kosong');
const instansi_id = body.instansi_id || 'bapperida';
const bulan = body.bulan || new Date().getMonth() + 1;
const tahun = body.tahun || new Date().getFullYear();
return rows.map(r => ({
  instansi_id: instansi_id,
  bulan: bulan,
  tahun: tahun,
  no_urut: r.no_urut || null,
  tgl: r.tgl || null,
  uraian: (r.uraian || '').replace(/'/g, "''"),
  kode_rekening: (r.kode_rekening || '').replace(/'/g, "''"),
  penerimaan: parseFloat(r.penerimaan) || 0,
  pengeluaran: parseFloat(r.pengeluaran) || 0,
  saldo: parseFloat(r.saldo) || 0
}));

