INSERT INTO "SIMAPO".bku (instansi_id, bulan, tahun, no_urut, tgl, uraian, kode_rekening, penerimaan, pengeluaran, saldo)
VALUES
{% for row in $json %}
  ('{{ row.instansi_id }}', {{ row.bulan }}, {{ row.tahun }}, {{ row.no_urut }}, '{{ row.tgl }}', '{{ row.uraian }}', '{{ row.kode_rekening }}', {{ row.penerimaan }}, {{ row.pengeluaran }}, {{ row.saldo }}){{ ',' if not loop.last }}
{% endfor %}
RETURNING id
